import java.util.HashMap

fun solve(nums: Array<Long>, k: Long): Long {
    var prefixSum = 0L
    val modMap = HashMap<Long, Long>()
    modMap[0] = 0L
    var dpPrev = 0L
    for (num in nums) {
        prefixSum += num
        val m = prefixSum % k
        var candidate = -Long.MAX_VALUE
        if (modMap.containsKey(m)) {
            candidate = modMap[m]!! + prefixSum
        }
        val dpCurrent = if (candidate > dpPrev) candidate else dpPrev
        val currentValue = dpCurrent - prefixSum
        if (modMap.containsKey(m)) {
            if (currentValue > modMap[m]!!) {
                modMap[m] = currentValue
            }
        } else {
            modMap[m] = currentValue
        }
        dpPrev = dpCurrent
    }
    return (prefixSum - dpPrev)
}
