    var dpPrev = 0L
    val remainderMap = HashMap<Long, Long>()
    remainderMap[0] = 0L

    for (num in nums) {
        preSum += num
        val currentRemainder = preSum % k
        var currentCandidate: Long = 0

        if (remainderMap.containsKey(currentRemainder)) {
            currentCandidate = remainderMap[currentRemainder]!! + preSum
        }

        val currentDp = if (remainderMap.containsKey(currentRemainder)) {
            max(dpPrev, currentCandidate)
        } else {
            dpPrev
        }

        val currentDpMinusPre = currentDp - preSum

        if (remainderMap.containsKey(currentRemainder)) {
            if (currentDpMinusPre > remainderMap[currentRemainder]!!) {
                remainderMap[currentRemainder] = currentDpMinusPre
            }
        } else {
            remainderMap[currentRemainder] = currentDpMinusPre
        }

        dpPrev = currentDp
    }

    return preSum - dpPrev
}
